import { Route, Routes, useNavigate } from 'react-router-dom';
import './App.css';
import Modal from './modal/Modal';

function App() {

  const navigation = useNavigate()

  const back = () => {
    navigation(-1)
  }

  let title = 'salom from to app'

  return (
  <div className='App'>

    <button onClick={() => navigation('modal')}>App</button>

    <Routes>
      <Route path='modal' element={<Modal title={title} back={back}/>}/>
    </Routes>
    <Modal>
      <h1>Nuriddin</h1>
        <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Quos adipisci qui, ex odit ad accusantium voluptate cum consectetur veniam deleniti?</p>
    </Modal>
  </div>
  );
}

export default App;
